36		if (symbol.getBody().kind == ast::StatementKind::Block ||
37				symbol.getBody().kind == ast::StatementKind::ConcurrentAssertion ||
38				symbol.getBody().kind == ast::StatementKind::ImmediateAssertion) {
39			// short-circuit for SVA; free-standing assertion
40			handle_comb_like_process(symbol, symbol.getBody());
41			return;
42		} else if (symbol.getBody().kind != ast::StatementKind::Timed) {
43			issuer.add_diag(diag::UnsynthesizableFeature, symbol.getBody().sourceRange.start());
44			return;
45		}
46	
47		const auto &timed = symbol.getBody().as<ast::TimedStatement>();
48		const auto *top_ast_timing = &timed.timing;
49	
50		using TCKind = ast::TimingControlKind;
51		std::span<const ast::TimingControl *const> events;
52		const ast::TimingControl *const top_events[1] = {top_ast_timing};
53	
54		events = (top_ast_timing->kind == TCKind::EventList)
55						 ? top_ast_timing->as<ast::EventListControl>().events
56						 : std::span<const ast::TimingControl *const>(top_events);
57	
58		bool implicit = false;
59		std::vector<const ast::SignalEventControl *> triggers;
60	
61		for (auto ev : events)
62			switch (ev->kind) {
63			case ast::TimingControlKind::SignalEvent: {
64				const auto &sigev = ev->as<ast::SignalEventControl>();
65	
66				if (sigev.iffCondition && sigev.edge == ast::EdgeKind::None)
67					issuer.add_diag(diag::IffUnsupported, sigev.iffCondition->sourceRange);
68	
69				switch (sigev.edge) {
70				case ast::EdgeKind::None: {
71					if (symbol.procedureKind == ast::ProceduralBlockKind::AlwaysFF) {
72						issuer.add_diag(diag::AlwaysFFBadTiming, ev->sourceRange);
73						break;
74					}
75	
76					// Report on the top timing node as that makes for nicer reports in case there
77					// are many signals in the sensitivity list
78					issuer.add_diag(diag::SignalSensitivityAmbiguous, top_ast_timing->sourceRange);
79					implicit = true;
